class Solution:
    def largestMagicSquare(self, grid):
        # Independent: brute force each subsquare by summing directly.
        m = len(grid)
        n = len(grid[0])
        def is_magic(r, c, k):
            target = sum(grid[r][c:c + k])
            for i in range(r, r + k):
                if sum(grid[i][c:c + k]) != target:
                    return False
            for j in range(c, c + k):
                s = 0
                for i in range(r, r + k):
                    s += grid[i][j]
                if s != target:
                    return False
            d1 = 0
            d2 = 0
            for i in range(k):
                d1 += grid[r + i][c + i]
                d2 += grid[r + i][c + k - 1 - i]
            return d1 == target and d2 == target
        for k in range(min(m, n), 0, -1):
            for r in range(m - k + 1):
                for c in range(n - k + 1):
                    if is_magic(r, c, k):
                        return k
        return 1

