class Solution:
    def largestMagicSquare(self, grid):
        m = len(grid)
        n = len(grid[0])
        rp = [[0] * (n + 1) for _ in range(m)]
        cp = [[0] * n for _ in range(m + 1)]
        for i in range(m):
            for j in range(n):
                rp[i][j + 1] = rp[i][j] + grid[i][j]
                cp[i + 1][j] = cp[i][j] + grid[i][j]
        def row_sum(i, c, k):
            return rp[i][c + k] - rp[i][c]
        def col_sum(j, r, k):
            return cp[r + k][j] - cp[r][j]
        def is_magic(r, c, k):
            target = row_sum(r, c, k)
            for i in range(r, r + k):
                if row_sum(i, c, k) != target:
                    return False
            for j in range(c, c + k):
                if col_sum(j, r, k) != target:
                    return False
            d1 = 0
            d2 = 0
            for i in range(k):
                d1 += grid[r + i][c + i]
                d2 += grid[r + i][c + k - 1 - i]
            return d1 == target and d2 == target
        for k in range(min(m, n), 0, -1):
            for r in range(m - k + 1):
                for c in range(n - k + 1):
                    if is_magic(r, c, k):
                        return k
        return 1

