var largestMagicSquare = function(grid) {
    const m = grid.length, n = grid[0].length;
    const rp = Array.from({length: m}, () => new Array(n + 1).fill(0));
    const cp = Array.from({length: m + 1}, () => new Array(n).fill(0));
    for (let i = 0; i < m; i++) for (let j = 0; j < n; j++) {
        rp[i][j + 1] = rp[i][j] + grid[i][j];
        cp[i + 1][j] = cp[i][j] + grid[i][j];
    }
    const rowSum = (i, c, k) => rp[i][c + k] - rp[i][c];
    const colSum = (j, r, k) => cp[r + k][j] - cp[r][j];
    const isMagic = (r, c, k) => {
        const target = rowSum(r, c, k);
        for (let i = r; i < r + k; i++) if (rowSum(i, c, k) !== target) return false;
        for (let j = c; j < c + k; j++) if (colSum(j, r, k) !== target) return false;
        let d1 = 0, d2 = 0;
        for (let i = 0; i < k; i++) { d1 += grid[r + i][c + i]; d2 += grid[r + i][c + k - 1 - i]; }
        return d1 === target && d2 === target;
    };
    for (let k = Math.min(m, n); k >= 1; k--) {
        for (let r = 0; r + k <= m; r++) {
            for (let c = 0; c + k <= n; c++) {
                if (isMagic(r, c, k)) return k;
            }
        }
    }
    return 1;
};
